// Aggregate stats from all platforms
const ig = $('Fetch Instagram Stats').all();
const tw = $('Fetch Twitter Stats').all();
const li = $('Fetch LinkedIn Stats').all();

const report = {
  period: { from: new Date(Date.now() - 7*24*60*60*1000).toISOString().split('T')[0], to: new Date().toISOString().split('T')[0] },
  instagram: {
    posts: ig.length,
    totalReach: ig.reduce((s, p) => s + (p.json.reach || 0), 0),
    totalLikes: ig.reduce((s, p) => s + (p.json.like_count || 0), 0),
    totalComments: ig.reduce((s, p) => s + (p.json.comments_count || 0), 0),
    topPost: ig.sort((a, b) => (b.json.reach || 0) - (a.json.reach || 0))[0]?.json.caption?.substring(0, 100) || 'N/A'
  },
  twitter: {
    tweets: tw.length,
    totalImpressions: tw.reduce((s, t) => s + (t.json.public_metrics?.impression_count || 0), 0),
    totalEngagements: tw.reduce((s, t) => s + (t.json.public_metrics?.like_count || 0) + (t.json.public_metrics?.retweet_count || 0), 0)
  },
  linkedin: {
    impressions: li.reduce((s, l) => s + (l.json.impressionCount || 0), 0),
    clicks: li.reduce((s, l) => s + (l.json.clickCount || 0), 0),
    engagement: li.reduce((s, l) => s + (l.json.engagement || 0), 0) / (li.length || 1)
  },
  weekOverWeek: 'Connect last week data for comparison'
};

return [{ json: report }];
